func maxWeight(weights []int, w1 int, w2 int) int {
	f := make([][]int, w1+1)
	for i := range f {
		f[i] = make([]int, w2+1)
	}
	for _, x := range weights {
		for j := w1; j >= 0; j-- {
			for k := w2; k >= 0; k-- {
				if x <= j {
					f[j][k] = max(f[j][k], f[j-x][k]+x)
				}
				if x <= k {
					f[j][k] = max(f[j][k], f[j][k-x]+x)
				}
			}
		}
	}
	return f[w1][w2]
}

